<!-- Closing tag on own line inside pre - tag should not break -->
<pre>
      <code>nested

        text

        as is
      </code>
</pre>

<!-- Closing tag on same line as content - no issue -->
<pre><code>text</code></pre>

<!-- Multi-line with closing on same line as last content -->
<pre>
      <code>nested

        text

        as is</code>
</pre>
